export type MailSummary = { id: string; accountId: string; threadId: string | null; subject: string; fromName: string | null; fromEmail: string; snippet: string | null; dateSent: number; isRead: boolean; hasAttachments: boolean }

/**
 * `mail:updated` — partial field update for one mail.
 */
export type MailUpdatedPayload = { id: string; isRead: boolean | null; isStarred: boolean | null }

/**
 * The assignment for one `(capability, account)` cell: a required primary
 * plus an ordered fallback chain (F_F4 §4.2). `resolve()` only ever returns
 * the primary; T067 walks `backups` after a primary failure via
 * [`AiRegistry::resolve_backup`](super::registry::AiRegistry::resolve_backup).
 */
export type MatrixCell = { primary: ProviderAssignment; backups?: ProviderAssignment[] }

/**
 * One matrix row binding for an account: capability → cell.
 */
export type MatrixEntry = { capability: Capability; cell: MatrixCell }

/**
 * One non-blocking save-time hint (F_F4 §4.5). `code` is a stable tag the
 * frontend maps to localized copy; `message` is the English fallback.
 */
export type MatrixWarning = { capability: Capability; code: string; message: string }

/**
 * One explicit or between-the-lines need (F_D2 §4.4). `evidence` is an
 * original-text snippet capped at 80 chars — enforced defensively at parse
 * time.
 */
export type NeedItem = { need: string; priority: NeedPriority; evidence: string }

/**
 * Priority of one identified need (F_D2 §4.4).
 */
export type NeedPriority = "high" | "medium" | "low"

/**
 * One recommended next step with its execution window (F_D2 §4.4).
 */
export type NextAction = { action: string; timeline: NextActionTimeline }

/**
 * Suggested execution window for one next action (F_D2 §4.4). Wire tags are
 * the D2 schema literals: `immediate` / `24h` / `72h` / `this_week`.
 */
export type NextActionTimeline = "immediate" | "24h" | "72h" | "this_week"

/**
 * What `begin_oauth_flow` returns to the UI (T015): just the authorize URL to
 * open. The PKCE verifier stays server-side; tokens never reach the frontend.
 */
export type OAuthBeginResult = { authorizeUrl: string }

/**
 * One model installed on a local daemon (F_F2 §4.3) — the wire shape of
 * `list_ollama_models`, projected from the adapter's `OllamaModelInfo`.
 */
export type OllamaModelEntry = { 
/**
 * Full model tag, e.g. `llama3:8b`.
 */
name: string; 
/**
 * On-disk weight size in bytes (0 when the daemon omits it).
 */
sizeBytes: number; 
/**
 * e.g. `8B` — from the daemon's `details.parameter_size`.
 */
parameterSize: string | null; 
/**
 * e.g. `Q4_0` — from the daemon's `details.quantization_level`.
 */
quantization: string | null }

/**
 * Generic paginated envelope (02 §Pagination). `total` is the full match count
 * so the UI can render pagination without a second query.
 */
export type PageResult<T> = { items: T[]; total: number; offset: number }

/**
 * One proactive query awaiting a human decision (`pending_queries`, T095/I3).
 * `content`-rich rendering lives in the `im_messages` query card (T098); this is
 * the lifecycle row the Pending DecisionCard (T099) and resume/expiry chains
 * (T096/T097) act on.
 */
export type PendingQuery = { id: string; accountId: string; mailId: string | null; riskEventId: string | null; 
/**
 * `T1`–`T6`.
 */
triggerType: string; question: string; 
/**
 * JSON array of option labels (the rich QA card content lives in im_messages).
 */
options: string | null; answer: string | null; 
/**
 * `pending` | `answered` | `skipped` | `expired`.
 */
status: string; 
/**
 * 1 (highest) – 5; T4 is always 1.
 */
priority: number; 
/**
 * `None` for T4 (never expires); otherwise `created_at + 72h`.
 */
expiresAt: number | null; answeredAt: number | null; createdAt: number }

/**
 * Result of the `ping` command — the first end-to-end IPC roundtrip (T002).
 * 
 * Started life as a bare `String` in T002 and was promoted to a named DTO in
 * T003 to establish the "every wire value is a named, generated type" pattern.
 */
export type PingReply = { 
/**
 * Always `"pong"` for a healthy backend.
 */
message: string }

/**
 * `pipeline:error` payload (T082) — one background pipeline job failed;
 * `error_code` is the wire `ErrorCode` string, never message text.
 */
export type PipelineErrorPayload = { mailId: string; errorCode: string }

/**
 * Mail provider family. Drives OAuth endpoint selection (T015) and is persisted
 * in `accounts.provider` as a lowercase string.
 */
export type Provider = "gmail" | "outlook" | "imap" | "exchange"

/**
 * One provider + model choice inside a cell (F_F4 §4.2).
 */
export type ProviderAssignment = { provider: AiProvider; 
/**
 * Model name at that provider. An empty string means "the provider's
 * default" (the local ONNX adapter auto-selects from its models folder).
 */
model: string; 
/**
 * Custom endpoint override; `None` = the provider's standard endpoint
 * (or, when the assignment keeps the account's base provider, the base
 * `ai_base_url`).
 */
baseUrl: string | null }

/**
 * Built-in provider connection hints (T014 autodiscover).
 */
export type ProviderHints = { imapHost: string; imapPort: number; imapTls: boolean; smtpHost: string; smtpPort: number; smtpTls: boolean }

export type QaCardContent = { cardVersion: number; 
/**
 * `pending_queries.id` this card resolves (used by T096 answer/skip).
 */
linkedQueryId: string; triggerType: string; 
/**
 * `high` | `normal` | `low`.
 */
priority: string; linkedEmailId: string | null; questionText: string; options: QaCardOption[]; multiSelect: boolean; freeTextPlaceholder: string | null; subQuestions: QaCardSubQuestion[]; response: QaCardResponse | null }

export type QaCardOption = { id: string; label: string; value: string }

export type QaCardResponse = { selectedOptionIds: string[]; freeText: string | null; submittedAt: number; actionResult: string | null }

export type QaCardSubQuestion = { questionText: string; options: QaCardOption[]; multiSelect: boolean }

/**
 * `query:expired` payload (T097/T101) — a query auto-expired (non-T4) or fired a
 * T4 reminder. Identifiers only.
 */
export type QueryExpiredPayload = { queryId: string; accountId: string; triggerType: string }

/**
 * `query:new` payload (T095/T101) — a proactive query was raised. Identifiers
 * only; `priority` is `"high"` (push a notification) or `"normal"` (badge only).
 */
export type QueryNewPayload = { queryId: string; accountId: string; priority: string }

/**
 * One knowledge-depth time bucket's estimate (T016). `None` fields mean the
 * sample timed out / couldn't be computed.
 */
export type RangeEstimate = { 
/**
 * `None` = "all mail"; `Some(n)` = last `n` months.
 */
months: number | null; mailCount: number | null; estimatedMb: number | null }

/**
 * One recipient (compose + send). `name` is optional; `email` is required.
 */
export type Recipient = { name: string | null; email: string }

/**
 * Payload of the [`OAUTH_CALLBACK_EVENT`] the deep-link handler emits.
 */
export type RecommendedOAuthCallback = { code: string; state: string }

/**
 * What the wizard renders per tier (F_F3 §3 step 2 + §4.4). Endpoint URLs
 * and env names are deliberately absent — the frontend never needs them.
 */
export type RecommendedProviderInfo = { tier: RecommendedTier; provider: AiProvider; model: string; displayName: string; monthlyCostMinUsd: number; monthlyCostMaxUsd: number; tokensPerReplyEstimate: number; 
/**
 * `false` = the wizard must use the authorization-code paste fallback.
 */
oauthSupported: boolean }

/**
 * The two recommendation tiers (F_F3 §3 step 2).
 */
export type RecommendedTier = "balanced" | "high_quality"

/**
 * Params for `regenerate_draft` (02 §Module E): supersede an existing draft
 * and generate a fresh one for the same trigger mail.
 */
export type RegenerateDraftParams = { 
/**
 * The draft being regenerated (it ends up `discarded`/`superseded`).
 */
id: string; instruction: string | null }

/**
 * Params for `request_ai_reply` (02 §Module E): generate an E1 manual reply
 * draft for one mail, with an optional steering instruction.
 */
export type RequestAiReplyParams = { mailId: string; instruction: string | null }

/**
 * `risk:alert` payload (T084) — an E4 interception (or any new risk event)
 * the UI should refetch risk queries for. Identifiers only.
 */
export type RiskAlertPayload = { riskEventId: string; mailId: string; accountId: string }

/**
 * The D2 sales analysis returned to the frontend (T072 §3). Also the exact
 * JSON persisted in `ai_decisions.action_description`, which backs the
 * 24-hour result cache.
 */
export type SalesAnalysisResult = { 
/**
 * `ai_decisions.id` of this analysis (the E7 audit row).
 */
decisionId: string; mailId: string; accountId: string; counterpartyProfile: CounterpartyProfile; needsAndIntents: NeedItem[]; concessionAdvice: ConcessionAdvice; nextActions: NextAction[]; 
/**
 * `None` when the counterparty has no `contacts` row (first contact).
 */
contactHistory: ContactHistorySummary | null; aiModel: string; 
/**
 * Mail ids of the GTE chunks that grounded the analysis (dev/06 §9).
 */
knowledgeRefs: string[]; createdAt: number }

/**
 * The six-bucket mailbox sample (T016).
 */
export type SamplingResult = { ranges: RangeEstimate[] }

/**
 * Params to upsert a compose draft (T045). `id` absent → create.
 */
export type SaveDraftParams = { id: string | null; accountId: string; to?: Recipient[]; cc?: Recipient[]; subject: string; bodyText: string; bodyHtml: string | null; inReplyTo: string | null }

/**
 * Params to create a saved search (T035).
 */
export type SaveSearchParams = { name: string; query: string; mode: string; accountId: string | null }

/**
 * A persisted saved search (01 `saved_searches`, T035).
 */
export type SavedSearch = { id: string; accountId: string | null; name: string; query: string; mode: string; sortOrder: number; createdAt: number }

/**
 * Relevance bucket for a result row (02 §SearchResult). high ≥ 0.7, mid ≥ 0.4.
 */
export type ScoreLabel = "high" | "mid" | "low"

/**
 * One recent search (01 `search_history`, T032/T034).
 */
export type SearchHistoryItem = { id: number; query: string; mode: string; resultCount: number | null; createdAt: number }

/**
 * Which search the combined command runs for the mail hits (T110).
 */
export type SearchMode = "keyword" | "semantic" | "auto"

/**
 * A single search hit, shared by keyword (C1) and semantic (C2) search.
 */
export type SearchResult = { mailId: string; accountId: string; subject: string; fromName: string | null; fromEmail: string; dateSent: number; snippet: string; 
/**
 * 0.0–1.0 — keyword: normalised BM25; semantic: cosine.
 */
score: number; scoreLabel: ScoreLabel; 
/**
 * Matched fragments with `<mark>…</mark>` tags (keyword search only).
 */
highlights: string[] }

/**
 * Params for `search_with_attachments` (T110 §3a).
 */
export type SearchWithAttachmentsParams = { query: string; mode: SearchMode; accountId: string | null; dateFrom: number | null; dateTo: number | null; limit: number | null }

/**
 * Combined result: mail-body hits + attachment-origin hits (T110 §3a).
 */
export type SearchWithAttachmentsResult = { mailHits: SearchResult[]; attachmentHits: AttachmentHit[] }

/**
 * Params for `semantic_search` (02 §Module C).
 */
export type SemanticSearchParams = { query: string; accountId: string | null; 
/**
 * Cross-account subset filter (T112). `None` = every active account;
 * `Some(ids)` = only those accounts. `account_id`, when set, takes
 * precedence (single-account path) for backward compatibility.
 */
accountFilter: string[] | null; dateFrom: number | null; dateTo: number | null; 
/**
 * Minimum cosine score; defaults to 0.35 when absent.
 */
minScore: number | null; limit: number; offset: number }

/**
 * Params for `send_mail` (02 §Module B/G). Recipients are typed addresses; the
 * HTML body is optional (plain-text-only messages are valid).
 */
export type SendMailParams = { accountId: string; to: Recipient[]; cc?: Recipient[]; bcc?: Recipient[]; subject: string; bodyText: string; bodyHtml: string | null; 
/**
 * Message-ID this is a reply to (drives thread association).
 */
inReplyTo: string | null; 
/**
 * Space-separated References chain (RFC 2822).
 */
references: string | null; 
/**
 * The draft this send finalises, if any (deleted on success, T045).
 */
draftId: string | null }

/**
 * `send_mail` result — the pending id (for cancel) + the message id (02 §3).
 */
export type SendMailResult = { pendingId: string; messageId: string }

/**
 * Parameters for `start_export` (T052). Credentials are structurally absent —
 * the export pipeline reads only `mails`/`attachments` rows.
 */
export type StartExportParams = { accountIds: string[]; 
/**
 * Unix seconds, inclusive lower bound. `None` = no lower bound.
 */
dateFrom: number | null; 
/**
 * Unix seconds, inclusive upper bound. `None` = no upper bound.
 */
dateTo: number | null; format: ExportFormat; includeBody: boolean; includeAttachments: boolean }

/**
 * `style:done` — the profile was written (or, for a pinned profile, the
 * sample count was refreshed).
 */
export type StyleDonePayload = { accountId: string; sampleCount: number }

/**
 * `style:error` — the run failed; `code` follows the standard wire table
 * (insufficient samples surfaces as `VALIDATION`, AI_MODES §6.7).
 */
export type StyleErrorPayload = { accountId: string; code: ErrorCode }

/**
 * The persisted style profile — stored verbatim in
 * `account_ai_settings.style_profile` and read back by T076 prompt injection
 * and the settings UI. Keys are deliberately `snake_case` (the stored schema
 * of F_E5 §4.2), unlike the camelCase event payloads below.
 */
export type StyleProfileJson = { version: number; account_id: string; 
/**
 * Unix timestamp (seconds) — drives the 30-day refresh check.
 */
generated_at: number; summary: StyleSummary; 
/**
 * Local-audit snippets (≤ 3 × 100 chars). Never injected into prompts.
 */
sample_snippets: string[]; 
/**
 * Set by the user when they hand-edit the summary (F_E5 §4.5); a pinned
 * profile is never overwritten by recomputes.
 */
pinned?: boolean }

/**
 * `style:progress` — one emission per stage: sampling → profiling → done.
 */
export type StyleProgressPayload = { accountId: string; 
/**
 * "sampling" | "profiling" | "done"
 */
stage: string; pct: number }

/**
 * The six style dimensions (F_E5 §4.2). Each text field is a short free-text
 * description (≤ ~80 words, enforced by prompt).
 */
export type StyleSummary = { overall_tone: string; opening_patterns: string[]; closing_patterns: string[]; sentence_length: string; vocabulary: string; format_habit: string }

/**
 * What the caller should do with the task that could not be served
 * (F_F5 §4.2). Every option keeps or increases human control — there is no
 * "send anyway" action by design (dev/06 §7 golden rule).
 */
export type SuggestedAction = 
/**
 * Keep the task queued; replay when a provider recovers (E2/E3, E5).
 */
"hold" | 
/**
 * Drop this background task; the per-account offline policy decides how
 * the mail is treated (E4 sensitivity pre-scan).
 */
"skip" | 
/**
 * Tell the human; the action was user-triggered (E1/D1/D2) or needs a
 * configuration fix.
 */
"prompt_user"

/**
 * `sync:complete`.
 */
export type SyncCompletePayload = { accountId: string; newCount: number }

/**
 * `sync:error`.
 */
export type SyncErrorPayload = { accountId: string; code: ErrorCode; message: string }

/**
 * `sync:progress`.
 */
export type SyncProgressPayload = { accountId: string; fetched: number; total: number | null; paused: boolean }

/**
 * Preview for a sync-range shrink (how many local mails fall outside).
 */
export type SyncRangePreview = { mailsBeyondRange: number }

/**
 * `sync:started`.
 */
export type SyncStartedPayload = { accountId: string }

/**
 * Per-account IMAP sync bookmark + health (01 `sync_state`, T021).
 */
export type SyncState = { accountId: string; lastSyncAt: number | null; lastSyncResult: string | null; consecutiveErrors: number; backoffUntil: number | null; inboxUidValidity: number | null; inboxUidNext: number | null; fullSyncRequired: boolean; totalMailsSynced: number; updatedAt: number }

/**
 * Tracker/remote-image status for one mail (T029).
 */
export type TrackerInfo = { blocked: boolean; trackerCount: number; imagesAllowed: boolean; senderEmail: string }

/**
 * Tracker-blocking policy, three levels (F_B2 §4.4). Persisted at
 * `app_settings.privacy.tracker_policy`; default `BlockKnown` (protection ON).
 */
export type TrackerPolicy = "block_all" | "block_known" | "allow_all"

/**
 * Partial update for an account (T013). `email` is intentionally absent — it is
 * immutable once an account is created.
 */
export type UpdateAccountParams = { displayName: string | null; colorToken: string | null; badgeLabel: string | null; roleType: string | null; roleDescription: string | null; authLevel: number | null; isActive: boolean | null; isPrimary: boolean | null; syncIntervalSecs: number | null; imapHost: string | null; imapPort: number | null; smtpHost: string | null; smtpPort: number | null }

/**
 * Partial update for `account_ai_settings` (02 §Module H). `ai_api_key` is
 * consumed at the command boundary and written to the Keychain — it is never
 * stored in a DB column and never echoed back to the frontend.
 */
export type UpdateAiSettingsParams = { authLevel: number | null; aiProvider: AiProvider | null; aiModel: string | null; 
/**
 * Written to the Keychain at the boundary; `None` = leave unchanged.
 */
aiApiKey: string | null; aiBaseUrl: string | null; t1Enabled: boolean | null; t2Enabled: boolean | null; t3Enabled: boolean | null; t4Enabled: boolean | null; t5Enabled: boolean | null; t6Enabled: boolean | null; dailyQueryLimit: number | null; e3WhitelistOnly: boolean | null; e3MinHistory: number | null }

/**
 * Outcome of an `upsert_batch` (T023).
 */
export type UpsertStats = { inserted: number; skippedDuplicate: number; parseErrors: number }

/**
 * Input to `verify_ai_provider` (02 §Module H): test a provider key/endpoint
 * without saving. The transient key exists only inside the command frame.
 */
export type VerifyAiProviderParams = { provider: AiProvider; model: string; apiKey: string | null; baseUrl: string | null }

/**
 * In-band result of `verify_ai_provider` (02 §Module H). The command returns
 * `Ok(_)` even when the probe fails (09 §2 in-band bucket); `error_message`
 * carries only the sanitized, content-free `ProviderError` rendering.
 */
export type VerifyAiProviderResult = { ok: boolean; 
/**
 * Confirmed model name from the provider, when it reports one.
 */
modelName: string | null; errorMessage: string | null }

/**
 * Input to the connection probe (T014). Plaintext `password` exists only inside
 * the probe's call frame; it is not stored anywhere.
 */
export type VerifyConnectionParams = { email: string; provider: Provider; password: string | null; imapHost: string | null; imapPort: number | null; imapTls: boolean | null; smtpHost: string | null; smtpPort: number | null; smtpTls: boolean | null }

/**
 * In-band probe result (T014). The command returns `Ok(_)` even on probe
 * failure; only internal errors escalate to `IpcError` (09 §2).
 */
export type VerifyConnectionResult = { imapOk: boolean; smtpOk: boolean; errorMessage: string | null }

/**
 * `wipe:complete`. `freed_bytes` is the estimate confirmed after VACUUM.
 */
export type WipeCompletePayload = { taskId: string; freedBytes: number }

/**
 * Impact preview shown before the `DELETE` confirmation step.
 */
export type WipePreview = { mailCount: number; attachmentCount: number; estimatedBytes: number }

/**
 * `wipe:progress` — emitted per deleted batch.
 */
export type WipeProgressPayload = { taskId: string; deleted: number; total: number }

/**
 * What a wipe removes (F_H2 §4.2 two-tier + full removal).
 */
export type WipeScope = 
/**
 * mails/threads/attachments rows + blobs; index untouched.
 */
"mails_only" | 
/**
 * Same + LanceDB vectors and FTS entries.
 */
"mails_and_index" | 
/**
 * Same + the account configuration row itself.
 */
"everything"

