// NOTE: AutoSentPayload / AutoLoopDetectedPayload / PipelineErrorPayload used to
// be hand-written here, but they are now registered from `crate::types` above and
// emitted in the generated section — keeping the manual copies produced duplicate
// identifiers on regeneration, so they were removed (T101 cleanup).

// ── Module E — E7 audit log decision types (dev/01 §ai_decisions) ───────────

/**
 * Known `ai_decisions.decision_type` values (dev/01 §ai_decisions). The wire
 * field stays `string` so unknown backend additions degrade gracefully in the
 * UI (chip falls back to the neutral token color).
 */
export const DECISION_TYPES = [
  "draft_created",
  "draft_sent",
  "draft_discarded",
  "draft_expired",
  "e3_auto_sent",
  "auto_reply_sent",
  "risk_intercepted",
  "e4_sensitive",
  "trust_downgraded",
] as const;

export type DecisionType = (typeof DECISION_TYPES)[number];
